class Solution {
    public int minimumScore(String s, String t) {
        int m = s.length(), n = t.length();
        int[] left = new int[n];
        int j = 0;
        for (int i = 0; i < m && j < n; i++) {
            if (s.charAt(i) == t.charAt(j)) {
                left[j++] = i;
            }
        }
        if (j != n) return n;

        int[] right = new int[n];
        j = n - 1;
        for (int i = m - 1; i >= 0 && j >= 0; i--) {
            if (s.charAt(i) == t.charAt(j)) {
                right[j--] = i;
            }
        }

        int minScore = n;
        j = 0;
        while (j < n && left[j] != -1) j++;
        if (j == n) minScore = Math.min(minScore, right[0] - left[n - 1] + 1);
        else minScore = Math.min(minScore, n);

        for (int i = 0; i < n; i++) {
            if (i > 0 && left[i - 1] == -1) break;
            while (j < n && right[j] <= left[i]) j++;
            if (j == n) {
                minScore = Math.min(minScore, right[n - 1] - left[i] + 1);
                break;
            }
            minScore = Math.min(minScore, right[j] - left[i] + 1);
        }
        return minScore;
    }
}
